## Eino 消息持久化最佳实践

### 1. 使用 Callbacks 机制捕获消息

Eino 提供了 `callbacks` 机制，可以在对话过程中捕获所有消息（包括用户消息、AI 回复、工具调用）：

```go
type MessageRecorder struct {
    callbacks.RunCallback
    messages []*schema.Message
    mu       sync.Mutex
}

func (r *MessageRecorder) OnEnd(ctx context.Context, info *callbacks.CallbackInput) {
    r.mu.Lock()
    defer r.mu.Unlock()
    // 捕获消息
    if msg := info.Message; msg != nil {
        r.messages = append(r.messages, msg)
    }
}
```

### 2. 自定义存储实现

将消息存储到数据库（如 MySQL、MongoDB、Redis）：

```go
type MessageStore interface {
    Save(ctx context.Context, sessionID string, messages []*Message) error
    Load(ctx context.Context, sessionID string) ([]*Message, error)
}

// MySQL 实现
type MySQLMessageStore struct {
    db *gorm.DB
}

func (s *MySQLMessageStore) Save(ctx context.Context, sessionID string, messages []*Message) error {
    return s.db.WithContext(ctx).Create(messages).Error
}

func (s *MySQLMessageStore) Load(ctx context.Context, sessionID string) ([]*Message, error) {
    var messages []*Message
    err := s.db.WithContext(ctx).
        Where("session_id = ?", sessionID).
        Order("created_at ASC").
        Find(&messages).Error
    return messages, err
}
```

### 3. 完整示例：持久化对话流程

```go
package main

import (
    "context"
    "time"

    "github.com/cloudwego/eino/schema"
)

// 消息结构
type PersistentMessage struct {
    ID        string    `gorm:"primaryKey"`
    SessionID string    `gorm:"index"`
    Role      string    // "user", "assistant", "tool"
    Content   string    `gorm:"type:text"`
    ToolCalls string    `gorm:"type:json"` // JSON 存储工具调用
    CreatedAt time.Time
}

// 持久化管理器
type PersistentMemory struct {
    store    MessageStore
    sessionID string
}

func (m *PersistentMemory) AddMessage(ctx context.Context, msg *schema.Message) error {
    // 转换并存储
    pMsg := &PersistentMessage{
        SessionID: m.sessionID,
        Role:      string(msg.Role),
        Content:   msg.Content,
        CreatedAt: time.Now(),
    }
    // 如果有工具调用，序列化存储
    if len(msg.ToolCalls) > 0 {
        toolCallsJSON, _ := json.Marshal(msg.ToolCalls)
        pMsg.ToolCalls = string(toolCallsJSON)
    }
    return m.store.Save(ctx, m.sessionID, []*PersistentMessage{pMsg})
}

func (m *PersistentMemory) GetHistory(ctx context.Context) ([]*schema.Message, error) {
    pMsgs, err := m.store.Load(ctx, m.sessionID)
    if err != nil {
        return nil, err
    }

    // 转换回 schema.Message
    var messages []*schema.Message
    for _, pMsg := range pMsgs {
        msg := &schema.Message{
            Role:    schema.RoleType(pMsg.Role),
            Content: pMsg.Content,
        }
        if pMsg.ToolCalls != "" {
            json.Unmarshal([]byte(pMsg.ToolCalls), &msg.ToolCalls)
        }
        messages = append(messages, msg)
    }
    return messages, nil
}
```

