## Eino 消息收集方法

### 方法一：通过 Callbacks 机制收集（推荐）

Callbacks 是 Eino 提供的回调机制，可以在执行过程中捕获所有消息：

```go
package main

import (
    "context"
    "fmt"

    "github.com/cloudwego/eino/callbacks"
    "github.com/cloudwego/eino/schema"
)

// 定义消息收集器
type MessageCollector struct {
    callbacks.RunCallback
    messages []*schema.Message
    toolCalls []schema.ToolCall
}

// 当 Run 结束时触发
func (c *MessageCollector) OnRunEnd(ctx context.Context, runInfo *callbacks.RunInfo, output *callbacks.RunOutput) {
    if output != nil && output.Message != nil {
        c.messages = append(c.messages, output.Message)

        // 收集工具调用
        if len(output.Message.ToolCalls) > 0 {
            c.toolCalls = append(c.toolCalls, output.Message.ToolCalls...)
        }
    }
}

// 使用示例
func main() {
    ctx := context.Background()

    // 创建消息收集器
    collector := &MessageCollector{
        messages: make([]*schema.Message, 0),
    }

    // 创建带回调的 context
    ctx = callbacks.SetCallbacks(ctx, collector)

    // 执行 chain 或 agent
    result, err := chain.Invoke(ctx, input)

    // 获取收集的消息
    fmt.Printf("收集到 %d 条消息\n", len(collector.messages))
    fmt.Printf("收集到 %d 次工具调用\n", len(collector.toolCalls))
}
```

### 方法二：自定义完整 Callback 实现

```go
package main

import (
    "context"
    "sync"
    "time"

    "github.com/cloudwego/eino/callbacks"
    "github.com/cloudwego/eino/schema"
)

// 消息记录
type MessageRecord struct {
    ID        string
    SessionID string
    Role      schema.RoleType
    Content   string
    ToolCalls []schema.ToolCall
    Timestamp time.Time
    Metadata  map[string]any
}

// 完整的消息收集回调
type PersistentCallback struct {
    callbacks.RunCallback
    sessionID string
    records   []MessageRecord
    mu        sync.Mutex
}

func (p *PersistentCallback) OnChatModelStart(ctx context.Context, info *callbacks.CallbackInput) {
    // 模型开始调用
}

func (p *PersistentCallback) OnChatModelEnd(ctx context.Context, out *callbacks.CallbackOutput) {
    p.mu.Lock()
    defer p.mu.Unlock()

    // 捕获模型输出
    if out.Message != nil {
        record := MessageRecord{
            SessionID: p.sessionID,
            Role:      out.Message.Role,
            Content:   out.Message.Content,
            ToolCalls: out.Message.ToolCalls,
            Timestamp: time.Now(),
        }
        p.records = append(p.records, record)
    }
}

func (p *PersistentCallback) OnToolStart(ctx context.Context, info *callbacks.CallbackInput) {
    // 工具开始调用
}

func (p *PersistentCallback) OnToolEnd(ctx context.Context, out *callbacks.CallbackOutput) {
    p.mu.Lock()
    defer p.mu.Unlock()

    // 捕获工具调用结果
    if out.Message != nil {
        record := MessageRecord{
            SessionID: p.sessionID,
            Role:      schema.Tool,
            Content:   out.Message.Content,
            Timestamp: time.Now(),
        }
        p.records = append(p.records, record)
    }
}

// 获取所有记录
func (p *PersistentCallback) GetRecords() []MessageRecord {
    p.mu.Lock()
    defer p.mu.Unlock()
    return p.records
}

// 清空记录
func (p *PersistentCallback) Clear() {
    p.mu.Lock()
    defer p.mu.Unlock()
    p.records = nil
}
```

### 方法三：使用 Context 传递并收集

```go
package main

import (
    "context"

    "github.com/cloudwego/eino/schema"
)

// context key
type messageKey struct{}

// 在 context 中设置消息收集器
func WithMessageCollector(ctx context.Context, collector *MessageCollector) context.Context {
    return context.WithValue(ctx, messageKey{}, collector)
}

// 从 context 获取收集器
func GetMessageCollector(ctx context.Context) *MessageCollector {
    if c, ok := ctx.Value(messageKey{}).(*MessageCollector); ok {
        return c
    }
    return nil
}

// 使用
func main() {
    ctx := context.Background()
    collector := &MessageCollector{}
    ctx = WithMessageCollector(ctx, collector)

    // 执行时会自动收集
    result, _ := agent.Invoke(ctx, input)

    // 获取收集的消息
    allMessages := collector.GetAll()
}
```

### 方法四：集成持久化存储

```go
package main

import (
    "context"
    "encoding/json"
    "time"

    "github.com/cloudwego/eino/callbacks"
    "github.com/cloudwego/eino/schema"
    "gorm.io/gorm"
)

// 数据库模型
type DBMessage struct {
    gorm.Model
    SessionID   string `gorm:"index"`
    Role        string
    Content     string `gorm:"type:text"`
    ToolCalls   string `gorm:"type:json"`
    ToolCallID  string
}

// 持久化回调
type PersistentCallback struct {
    callbacks.RunCallback
    db        *gorm.DB
    sessionID string
}

func (p *PersistentCallback) saveMessage(msg *schema.Message) error {
    toolCallsJSON, _ := json.Marshal(msg.ToolCalls)

    dbMsg := &DBMessage{
        SessionID: p.sessionID,
        Role:      string(msg.Role),
        Content:   msg.Content,
        ToolCalls: string(toolCallsJSON),
    }

    // 如果是工具响应
    if msg.ToolCallID != "" {
        dbMsg.ToolCallID = msg.ToolCallID
    }

    return p.db.Create(dbMsg).Error
}

// 回调结束时保存
func (p *PersistentCallback) OnChatModelEnd(ctx context.Context, out *callbacks.CallbackOutput) {
    if out.Message != nil {
        p.saveMessage(out.Message)
    }
}

func (p *PersistentCallback) OnToolEnd(ctx context.Context, out *callbacks.CallbackOutput) {
    if out.Message != nil {
        p.saveMessage(out.Message)
    }
}
```

### 完整使用示例

```go
package main

import (
    "context"
    "fmt"

    "github.com/cloudwego/eino/callbacks"
    "github.com/cloudwego/eino/compose"
    "github.com/cloudwego/eino/schema"
)

func main() {
    ctx := context.Background()

    // 1. 创建消息收集器
    collector := &PersistentCallback{
        sessionID: "session-123",
        records:   make([]MessageRecord, 0),
    }

    // 2. 设置回调到 context
    ctx = callbacks.SetRunCallback(ctx, collector)

    // 3. 创建并执行 chain/agent
    chain := compose.NewChain()
    // ... 配置 chain

    // 4. 执行
    input := []*schema.Message{
        {Role: schema.User, Content: "帮我查询今天的天气"},
    }

    result, err := chain.Invoke(ctx, input)
    if err != nil {
        panic(err)
    }

    // 5. 获取所有收集的消息
    records := collector.GetRecords()
    for _, r := range records {
        fmt.Printf("[%s] %s: %s\n", r.Timestamp, r.Role, r.Content)
        if len(r.ToolCalls) > 0 {
            fmt.Printf("  工具调用: %+v\n", r.ToolCalls)
        }
    }
}
```

---

## 总结

| 方法 | 适用场景 | 优点 | 缺点 |
|------|----------|------|------|
| **Callbacks** | 生产环境推荐 | 不侵入业务代码，自动收集 | 需要理解回调机制 |
| **Context 传递** | 简单场景 | 灵活，可控制 | 需要手动调用 |
| **直接获取结果** | 单次对话 | 简单直接 | 无法收集中间消息 |

**推荐使用 Callbacks 机制**，它可以在不修改业务逻辑的情况下，自动收集所有对话消息和工具调用。

